import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import { Header } from './components/Header';
import { ProductList } from './components/ProductList';
import { OrderSidebar } from './components/OrderSidebar';
import { products } from './constants';
import type { Product, CartItem, CustomerInfo } from './types';
import { Modal } from './components/Modal';
import { AddToCartModal } from './components/AddToCartModal';
import { ProductDetailPage } from './components/ProductDetailPage';
import { RamadanPromoBanner } from './components/RamadanPromoBanner';
import { BottomNavBar } from './components/BottomNavBar';

const App: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [customerInfo, setCustomerInfo] = useState<CustomerInfo>({
    name: '',
    phone: '',
    address: '',
    postalCode: '',
  });
  const [selectedBonus, setSelectedBonus] = useState<string>('');

  const [isOrderSuccessModalVisible, setIsOrderSuccessModalVisible] = useState(false);
  const [whatsappUrl, setWhatsappUrl] = useState('');

  const [lastAddedProduct, setLastAddedProduct] = useState<Product | null>(null);
  const [isAddToCartModalVisible, setIsAddToCartModalVisible] = useState(false);

  const [activeTab, setActiveTab] = useState('home');

  const sidebarRef = useRef<HTMLDivElement>(null);
  const promoRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const wedhangQuantity = cartItems
        .filter(item => item.category === 'Wedhang Cafe JSR')
        .reduce((sum, item) => sum + item.quantity, 0);
    const freeGifts = Math.floor(wedhangQuantity / 3);
    if (freeGifts === 0) {
        setSelectedBonus('');
    }
  }, [cartItems]);

  const handleContinueToWhatsapp = () => {
    if (whatsappUrl) {
      window.open(whatsappUrl, '_blank');
    }
    setIsOrderSuccessModalVisible(false);
    setWhatsappUrl('');
    // Clear cart and customer info
    setCartItems([]);
    setCustomerInfo({
      name: '',
      phone: '',
      address: '',
      postalCode: '',
    });
  };

  const handleScrollToSidebar = () => {
    sidebarRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    setActiveTab('cart');
  };

  const handleNavigate = (tab: string) => {
    setActiveTab(tab);
    if (tab === 'promo') {
      promoRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    } else if (tab === 'cart') {
      sidebarRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    } else if (tab === 'home') {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleAddToCart = useCallback((product: Product) => {
    setCartItems(prevItems => {
      const exist = prevItems.find(item => item.id === product.id);
      if (exist) {
        return prevItems.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      } else {
        return [...prevItems, { ...product, quantity: 1 }];
      }
    });

    setLastAddedProduct(product);
    setIsAddToCartModalVisible(true);

    if (sidebarRef.current) {
      sidebarRef.current.classList.remove('animate-pulse-once');
      void sidebarRef.current.offsetWidth; 
      sidebarRef.current.classList.add('animate-pulse-once');
    }
  }, []);

  const handleModalContinueShopping = () => {
    setIsAddToCartModalVisible(false);
  };

  const handleModalCheckout = () => {
    setIsAddToCartModalVisible(false);
    handleScrollToSidebar();
  };


  const handleUpdateQuantity = useCallback((productId: number, newQuantity: number) => {
    setCartItems(prevItems => {
      if (newQuantity <= 0) {
        return prevItems.filter(item => item.id !== productId);
      }
      return prevItems.map(item =>
        item.id === productId ? { ...item, quantity: newQuantity } : item
      );
    });
  }, []);

  const handleRemoveFromCart = useCallback((productId: number) => {
    setCartItems(prevItems => prevItems.filter(item => item.id !== productId));
  }, []);

  const totalItems = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  const MainLayout: React.FC = () => (
    <main className="container mx-auto px-4 py-8">
      <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-12">
        <div className="lg:col-span-2">
          <div ref={promoRef}>
            <RamadanPromoBanner />
          </div>
          <div className="mt-8">
            <ProductList 
              products={products} 
              onAddToCart={handleAddToCart}
            />
          </div>
        </div>
        <div className="lg:col-span-1 mt-8 lg:mt-0" ref={sidebarRef}>
          <OrderSidebar 
            items={cartItems} 
            onUpdateQuantity={handleUpdateQuantity} 
            onRemoveFromCart={handleRemoveFromCart} 
            customerInfo={customerInfo}
            setCustomerInfo={setCustomerInfo}
            selectedBonus={selectedBonus}
            setSelectedBonus={setSelectedBonus}
            setIsOrderSuccessModalVisible={setIsOrderSuccessModalVisible}
            setWhatsappUrl={setWhatsappUrl}
          />
        </div>
      </div>
      <BottomNavBar 
        activeTab={activeTab}
        onNavigate={handleNavigate}
        cartItemCount={totalItems}
      />
    </main>
  );

  return (
    <div className="min-h-screen bg-stone-200 font-sans">
      <div className="min-h-screen bg-stone-100 font-sans pb-24 lg:pb-0 max-w-7xl mx-auto shadow-2xl">
        <Header />

        <Routes>
          <Route path="/" element={<MainLayout />} />
          <Route 
            path="/product/:productId" 
            element={<ProductDetailPage products={products} onAddToCart={handleAddToCart} />} 
          />
        </Routes>

        <AddToCartModal 
            isVisible={isAddToCartModalVisible}
            product={lastAddedProduct}
            onClose={handleModalContinueShopping}
            onCheckout={handleModalCheckout}
            cartItems={cartItems}
        />

        <Modal 
          isVisible={isOrderSuccessModalVisible}
          onConfirm={handleContinueToWhatsapp}
          onClose={() => setIsOrderSuccessModalVisible(false)}
          title="Pesanan Berhasil Terkirim!"
          message="Data pesanan Anda telah kami terima. Silakan lanjutkan ke WhatsApp untuk konfirmasi dengan admin kami."
          confirmText="Lanjutkan ke WhatsApp"
        />
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import type { Product } from '../types';
import { ProductCard } from './ProductCard';
import { SpecialOfferCard } from './SpecialOfferCard';
import { BenefitTags } from './BenefitTags';

interface ProductListProps {
  products: Product[];
  onAddToCart: (product: Product) => void;
}

const categoryDescriptions: Record<string, string> = {
    'Snack Plizstop': 'Snack Plizstop adalah snack sehat berbahan dasar tapioka berkualitas Gluten Free dan MSG Free. Rasanya gurih renyah, cocok buat camilan atau topping makanan.',
    'Wedhang Cafe JSR': 'Wedang Cafe JSR adalah minuman rempah asli alami premium yang praktis, tinggal seduh air panas. Tanpa bahan pengawet, InsyaAllah aman untuk ikhtiar kesehatan harian.'
}

const categoryOrder = ['Snack Plizstop', 'Wedhang Cafe JSR'];

export const ProductList: React.FC<ProductListProps> = ({ products, onAddToCart }) => {
  // Find the special offer product
  const specialOfferProduct = products.find(p => p.isSpecialOffer);
  // Filter out the special offer product for normal listing
  const regularProducts = products.filter(p => !p.isSpecialOffer);

  const groupedProducts = regularProducts.reduce((acc, product) => {
    (acc[product.category] = acc[product.category] || []).push(product);
    return acc;
  }, {} as Record<string, Product[]>);

  const handleBenefitClick = (productId: number) => {
    const element = document.getElementById(`product-${productId}`);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      element.classList.add('animate-highlight-scroll');
      setTimeout(() => {
        element.classList.remove('animate-highlight-scroll');
      }, 1000);
    }
  };

  return (
    <div className="space-y-12">
      {/* Render the special offer card at the top */}
      {specialOfferProduct && (
        <section>
          <h2 className="text-3xl font-bold text-gray-800">Penawaran Spesial</h2>
          <p className="mt-2 text-gray-600">Jangan lewatkan paket spesial Ramadhan & Lebaran kami!</p>
          <div className="mt-6">
            <SpecialOfferCard 
              product={specialOfferProduct}
              onAddToCart={onAddToCart}
            />
          </div>
        </section>
      )}


      {categoryOrder.map((category) => {
        const items = groupedProducts[category];
        if (!items || items.length === 0) return null;

        const wedhangBenefits = category === 'Wedhang Cafe JSR' 
            ? items
                .filter(p => p.name.startsWith('Wedhang '))
                .map(p => ({
                    label: p.name.replace('Wedhang ', '').replace(' Hangat Menyapa', ''),
                    productId: p.id
                })) 
            : [];

        return (
          <section key={category}>
            <h2 className="text-3xl font-bold text-gray-800">{category}</h2>
            <p className="mt-2 text-gray-600">{categoryDescriptions[category]}</p>

            {category === 'Wedhang Cafe JSR' && (
                <BenefitTags benefits={wedhangBenefits} onBenefitClick={handleBenefitClick} />
            )}

            <div className="mt-4 inline-block">
               <span className="bg-green-forest/10 text-green-forest text-sm font-medium px-3 py-1 rounded-full">{items[0].tag}</span>
            </div>
            <div className="mt-6 grid grid-cols-2 gap-4">
              {items.map(product => (
                <ProductCard key={product.id} product={product} onAddToCart={onAddToCart} />
              ))}
            </div>
          </section>
        )
      })}
    </div>
  );
};

